{"path": "/tmp/sv-548f1092a9a047dda90719bba431d542/Components/Catalog/CatalogPagination.razor", "file_text": "<nav aria-label="Product pagination">
    <ul class="pagination justify-content-center mb-0">
        <li class="page-item @(Page <= 1 ? "disabled" : "")">
            <button class="page-link" @onclick="@(() => GoToPage(Page - 1))" disabled="@(Page <= 1)">
                Previous
            </button>
        </li>
        @for (int i = 1; i <= TotalPages; i++)
        {
            var pageNumber = i;
            <li class="page-item @(pageNumber == Page ? "active" : "")">
                <button class="page-link" @onclick="@(() => GoToPage(pageNumber))">
                    @pageNumber
                </button>
            </li>
        }
        <li class="page-item @(Page >= TotalPages ? "disabled" : "")">
            <button class="page-link" @onclick="@(() => GoToPage(Page + 1))" disabled="@(Page >= TotalPages)">
                Next
            </button>
        </li>
    </ul>
</nav>

@code {
    [Parameter]
    public int Page { get; set; }

    [Parameter]
    public int TotalPages { get; set; }

    [Parameter]
    public EventCallback<int> OnPageChanged { get; set; }

    private async Task GoToPage(int page)
    {
        if (page >= 1 && page <= TotalPages)
        {
            await OnPageChanged.InvokeAsync(page);
        }
    }
}
"}

